
INSERT INTO public.paths (id, name, region, type, latitude, longitude, cover_image, image_day, image_night, content, goods_type) VALUES
('arch-seonam-shortcut','선암호수 벤치, 아무것도 안 해도 되는 곳','남구','갓길',35.5093,129.3174,'pick-seonam',
 'https://images.unsplash.com/photo-1502082553048-f009c37129b9?w=1600&q=80&auto=format&fit=crop',
 'https://images.unsplash.com/photo-1419242902214-272b3f66ee7a?w=1600&q=80&auto=format&fit=crop',
 '{"story":"호수 옆 벤치에 앉으면 시간이 다르게 흐른다. 오리들이 물 위를 지나가고, 바람이 불어오고, 아무것도 하지 않아도 괜찮다는 기분이 조용히 찾아오는 울산의 갓길.","route":[{"step":"01","text":"선암호수공원 정문에서 시계 반대 방향으로 출발."},{"step":"02","text":"호수를 따라 5분, 첫 번째 그늘 벤치에서 한 번 멈춰요."},{"step":"03","text":"호수 동편 데크길을 끝까지. 여기까지 약 25분."}],"tidbits":["오후 4시쯤 햇빛이 호수에 닿는 각도가 가장 예쁩니다.","평일 오전엔 인적이 거의 없어요."]}'::jsonb,'wallpaper'),
('arch-seongnam-flower','성남동 꽃담 골목','중구','샛길',35.5587,129.3151,'pick-seongnam',
 'https://images.unsplash.com/photo-1480714378408-67cf0d13bc1b?w=1600&q=80&auto=format&fit=crop',
 'https://images.unsplash.com/photo-1519681393784-d120267933ba?w=1600&q=80&auto=format&fit=crop',
 '{"story":"번화가 뒤편으로 한 블록만 들어가면 오래된 담벼락에 꽃이 피어있다. 관광 안내도에는 없는 그 골목이 이 도시에서 가장 예쁜 샛길이다.","route":[{"step":"01","text":"성남동 번영로 카페 거리 입구에서 좌회전."},{"step":"02","text":"좁은 골목으로 두 번째 모퉁이까지 직진."},{"step":"03","text":"꽃담 벽 앞에서 잠시. 사진을 남겨도 좋아요."}],"tidbits":["봄에는 능소화, 가을엔 담쟁이가 색을 바꿔요.","주말 오후엔 사람이 몰리니 평일을 추천."]}'::jsonb,'wallpaper'),
('arch-hakseong-trail','학성공원 우회 산책로','중구','지름길',35.5644,129.3422,'pick-hakseong',
 'https://images.unsplash.com/photo-1441974231531-c6227db76b6e?w=1600&q=80&auto=format&fit=crop',
 'https://images.unsplash.com/photo-1507608616759-54f48f0af0ee?w=1600&q=80&auto=format&fit=crop',
 '{"story":"정식 등산로를 따라가면 돌아가는 길, 공원 북쪽 담장을 따라 걸으면 30분이 절약된다. 게다가 중간에 나오는 전망 포인트는 정식 코스에는 없다.","route":[{"step":"01","text":"학성공원 북문 — 담장을 따라 동쪽으로."},{"step":"02","text":"세 번째 갈림길에서 위쪽 능선을 선택."},{"step":"03","text":"전망바위에서 도시의 동쪽 풍경을 확인."}],"tidbits":["아침 7~9시 사이 빛이 가장 부드럽습니다.","비온 다음날엔 흙길이 미끄러우니 주의."]}'::jsonb,'wallpaper'),
('arch-samsan-alley','삼산동 주택가 골목','남구','샛길',35.5402,129.3389,'arch-samsan-alley',
 'https://images.unsplash.com/photo-1505852679233-d9fd70aff56d?w=1600&q=80&auto=format&fit=crop',
 'https://images.unsplash.com/photo-1519111192146-d2bb1d2b2da4?w=1600&q=80&auto=format&fit=crop',
 '{"story":"삼산동 한가운데, 격자처럼 짜인 주택가 사이로 작은 골목들이 숨어 있다. 빨래가 펄럭이고, 화분이 줄지어 있고, 평범하지만 그래서 더 좋은 길.","route":[{"step":"01","text":"삼산동 행정복지센터 뒤편에서 시작."},{"step":"02","text":"두 블록 직진 후 우회전, 작은 슈퍼 옆 골목."},{"step":"03","text":"골목 끝에서 큰 길과 다시 만남."}],"tidbits":["저녁 무렵 창문에서 새어나오는 불빛이 따뜻해요."]}'::jsonb,'wallpaper'),
('arch-jangseongpo','장생포 고래문화마을','남구','갓길',35.5028,129.3692,'arch-jangseongpo',
 'https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=1600&q=80&auto=format&fit=crop',
 'https://images.unsplash.com/photo-1493514789931-586cb221d7a7?w=1600&q=80&auto=format&fit=crop',
 '{"story":"옛 포경 마을의 자취가 남아있는 골목. 바다 냄새와 페인트가 벗겨진 담벼락이 만들어내는 풍경이 묘하게 따뜻하다.","route":[{"step":"01","text":"고래박물관 앞 광장에서 출발."},{"step":"02","text":"벽화 골목을 따라 항구 쪽으로."},{"step":"03","text":"방파제 끝에서 바다를 정면으로."}],"tidbits":["일몰 직전 항구의 빛이 가장 좋습니다."]}'::jsonb,'wallpaper'),
('arch-sinjeong-mural','신정동 벽화 골목','남구','샛길',35.5387,129.3220,'arch-sinjeong-mural',
 'https://images.unsplash.com/photo-1518998053901-5348d3961a04?w=1600&q=80&auto=format&fit=crop',
 'https://images.unsplash.com/photo-1517457373958-b7bdd4587205?w=1600&q=80&auto=format&fit=crop',
 '{"story":"학교 담벼락을 따라 그려진 벽화들. 누군가의 졸업작품이 그대로 남아 골목의 분위기를 바꿔놓았다.","route":[{"step":"01","text":"신정초 정문에서 좌측 골목으로."},{"step":"02","text":"벽화를 따라 5분 천천히."}],"tidbits":["하굣길 시간엔 동네 아이들 소리가 배경이 돼요."]}'::jsonb,'wallpaper'),
('arch-namgu-riverside','남구 강변 둘레길','남구','갓길',35.5462,129.3265,'arch-namgu-riverside',
 'https://images.unsplash.com/photo-1426604966848-d7adac402bff?w=1600&q=80&auto=format&fit=crop',
 'https://images.unsplash.com/photo-1502082553048-f009c37129b9?w=1600&q=80&auto=format&fit=crop',
 '{"story":"태화강 남쪽 강변을 따라 자전거 도로와 산책로가 나란히. 바람과 물의 소리가 함께 흐르는 길.","route":[{"step":"01","text":"삼호교 남단에서 출발, 동쪽으로."},{"step":"02","text":"갈대밭 구간을 천천히 통과."},{"step":"03","text":"태화교 아래에서 마무리."}],"tidbits":["가을 갈대가 황금빛으로 물들 때가 절정."]}'::jsonb,'wallpaper'),
('arch-sinjeong-market','신정 시장 뒷길','남구','지름길',35.5371,129.3268,'arch-sinjeong-market',
 'https://images.unsplash.com/photo-1555992336-fb0d29498b13?w=1600&q=80&auto=format&fit=crop',
 'https://images.unsplash.com/photo-1555992457-b8fefdd70bef?w=1600&q=80&auto=format&fit=crop',
 '{"story":"시장 정문이 아닌 뒷문으로 들어가면 사람이 절반인 골목과 빠른 지름길이 동시에 열린다.","route":[{"step":"01","text":"시장 북쪽 주차장 옆 좁은 입구."},{"step":"02","text":"좌판 사이를 빠르게 가로질러요."}],"tidbits":["아침 9시 전엔 거의 비어 있어요."]}'::jsonb,'wallpaper'),
('arch-taehwa-reeds','태화강 둔치 억새밭','중구','갓길',35.5544,129.3196,'arch-taehwa-reeds',
 'https://images.unsplash.com/photo-1500382017468-9049fed747ef?w=1600&q=80&auto=format&fit=crop',
 'https://images.unsplash.com/photo-1490604001847-b712b0c2f967?w=1600&q=80&auto=format&fit=crop',
 '{"story":"바람이 부는 날, 둔치의 억새는 통째로 한 방향으로 휘어진다. 그 위로 햇빛이 지나가는 모습은 도시 안에서 만날 수 있는 가장 큰 풍경 중 하나.","route":[{"step":"01","text":"태화강 국가정원 입구에서 강쪽으로."},{"step":"02","text":"억새밭 산책로를 따라 천천히."},{"step":"03","text":"십리대숲 입구까지."}],"tidbits":["밤이 되면 십리대숲의 조명이 켜집니다."]}'::jsonb,'wallpaper'),
('arch-jungang-market','중앙시장 뒷골목','중구','샛길',35.5601,129.3349,'arch-jungang-market',
 'https://images.unsplash.com/photo-1555992336-03a23f1de0a4?w=1600&q=80&auto=format&fit=crop',
 'https://images.unsplash.com/photo-1517248135467-4c7edcad34c4?w=1600&q=80&auto=format&fit=crop',
 '{"story":"시장의 활기가 한 블록 너머로도 이어진다. 오래된 간판과 좁은 골목, 그리고 그곳에서만 파는 작은 가게들.","route":[{"step":"01","text":"중앙시장 동문에서 출발."},{"step":"02","text":"좁은 골목으로 한 번, 다시 한 번."}],"tidbits":["오래된 분식집의 떡볶이가 유명해요."]}'::jsonb,'wallpaper'),
('arch-taehwa-bridge','태화교 다리 산책길','중구','갓길',35.5567,129.3232,'arch-taehwa-bridge',
 'https://images.unsplash.com/photo-1470770841072-f978cf4d019e?w=1600&q=80&auto=format&fit=crop',
 'https://images.unsplash.com/photo-1505765050516-f72dcac9c60a?w=1600&q=80&auto=format&fit=crop',
 '{"story":"다리 위에서 보는 태화강은 둔치에서 보는 것과 다르다. 도시와 강이 한 프레임에 들어오는 자리.","route":[{"step":"01","text":"태화교 남단 보행로 입구."},{"step":"02","text":"중앙까지 천천히, 풍경 감상."},{"step":"03","text":"북단 계단으로 내려와 강변과 합류."}],"tidbits":["일몰 30분 전이 가장 아름답습니다."]}'::jsonb,'wallpaper'),
('arch-hakseong-ridge','학성 능선 지름길','중구','지름길',35.5667,129.3445,'arch-hakseong-ridge',
 'https://images.unsplash.com/photo-1506905925346-21bda4d32df4?w=1600&q=80&auto=format&fit=crop',
 'https://images.unsplash.com/photo-1518709268805-4e9042af2176?w=1600&q=80&auto=format&fit=crop',
 '{"story":"학성 동쪽 능선을 따라 짧게 오르면, 동네를 통째로 내려다보는 자리가 나온다. 등산이라기엔 짧고, 산책이라기엔 약간 가파른 길.","route":[{"step":"01","text":"학성동 동쪽 등산로 입구."},{"step":"02","text":"가파른 첫 5분 — 천천히."},{"step":"03","text":"능선 정상 평지에서 한 바퀴."}],"tidbits":["여름엔 모기가 많으니 긴팔 권장."]}'::jsonb,'wallpaper')
ON CONFLICT (id) DO NOTHING;
